class CombinationIterator {
private:
    string characters;
    int combinationLength;
    vector<int> indices;
    bool has_next;

public:
    CombinationIterator(string characters, int combinationLength) : characters(characters), combinationLength(combinationLength) {
        indices.resize(combinationLength);
        for (int i = 0; i < combinationLength; ++i) {
            indices[i] = i;
        }
        has_next = true;
        if (combinationLength > characters.size()) {
            has_next = false;
        }
    }

    string next() {
        string result;
        for (int i = 0; i < combinationLength; ++i) {
            result += characters[indices[i]];
        }
        int i = combinationLength - 1;
        while (i >= 0 && indices[i] == characters.size() - combinationLength + i) {
            --i;
        }
        if (i < 0) {
            has_next = false;
        } else {
            ++indices[i];
            for (int j = i + 1; j < combinationLength; ++j) {
                indices[j] = indices[j - 1] + 1;
            }
        }
        return result;
    }

    bool hasNext() {
        return has_next;
    }
};

